{
  "name": "OneStock Wave Orchestrator",
  "description": "An advanced order orchestration management platform for retail logistics, allowing users to select orders, define orchestration scenarios, simulate outcomes, and compare results for optimal fulfillment strategy selection."
}

export interface Condition {
  id: string;
  field: string;
  operator: string;
  value: string;
  joiner?: 'AND' | 'OR';
}

export interface Scenario {
  id: string;
  name: string;
  description: string;
  rules: string[];
  metrics: {
    fulfillmentRate: number;
    shippingCost: number;
    deliveryTime: number;
    carbonFootprint: number;
  };
}

export interface Order {
  id: string;
  client: string;
  priority: 'P1' | 'P2' | 'P3';
  sku: string;
  quantity: number;
  date: string;
  channel: string;
  status: string;
  proposedStockPoint?: string;
}

export enum Step {
  OrderSelection = 1,
  OrchestrationScenarios = 2,
  ResultsVisualization = 3,
  Comparison = 4,
  FinalSelection = 5
}

import { Order, Scenario } from './types';

export const COLORS = {
  primary: '#00A79D', // OneStock Teal
  secondary: '#2D3E50', // Dark Blue
  accent: '#F39C12', // Orange
  success: '#27AE60',
  error: '#E74C3C',
};

