export const FIELDS = ['Sales Channel', 'Order Date', 'Priority', 'Destination Country', 'Stock Level', 'Carrier'];
export const OPERATORS = ['is', 'is not', 'contains', 'greater than', 'less than'];

import React from 'react';
import { Step } from '../types';

interface StepperProps {
  currentStep: Step;
}

export const Stepper: React.FC<StepperProps> = ({ currentStep }) => {
  const steps = [
    { id: 1, label: 'Order Selection' },
    { id: 2, label: 'Orchestration Scenarios' },
    { id: 3, label: 'Results Visualization' },
    { id: 4, label: 'Comparison' },
    { id: 5, label: 'Final Selection' },
  ];

  return (
    <div className="w-full py-6">
      <div className="flex items-center justify-between">
        {steps.map((step, idx) => (
          <React.Fragment key={step.id}>
            <div className="flex flex-col items-center flex-1">
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-300 border-2 ${
                  currentStep === step.id
                    ? 'bg-[#00A79D] text-white border-[#00A79D]'
                    : currentStep > step.id
                    ? 'bg-emerald-50 text-[#00A79D] border-[#00A79D]'
                    : 'bg-white text-slate-400 border-slate-200'
                }`}
              >
                {currentStep > step.id ? (
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                ) : (
                  step.id
                )}
              </div>
              <span className={`text-[10px] mt-2 font-semibold uppercase tracking-wide text-center px-1 ${
                currentStep === step.id ? 'text-slate-900' : 'text-slate-400'
              }`}>
                {step.label}
              </span>
            </div>
            {idx < steps.length - 1 && (
              <div className={`h-[2px] flex-1 -mt-5 ${currentStep > step.id ? 'bg-[#00A79D]' : 'bg-slate-200'}`} />
            )}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Condition } from '../types';
import { FIELDS, OPERATORS } from '../constants';

interface ConditionBuilderProps {
  conditions: Condition[];
  onAdd: (c: Condition) => void;
  onRemove: (id: string) => void;
}

export const ConditionBuilder: React.FC<ConditionBuilderProps> = ({ conditions, onAdd, onRemove }) => {
  const [newCondition, setNewCondition] = useState<Partial<Condition>>({
    field: FIELDS[0],
    operator: OPERATORS[0],
    value: '',
    joiner: 'AND'
  });

  const handleAdd = () => {
    if (newCondition.value) {
      onAdd({
        id: Math.random().toString(36).substr(2, 9),
        field: newCondition.field!,
        operator: newCondition.operator!,
        value: newCondition.value!,
        joiner: conditions.length > 0 ? newCondition.joiner : undefined
      });
      setNewCondition({ ...newCondition, value: '' });
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
      <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
        <svg className="w-5 h-5 text-[#00A79D]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
        Order Selection Filters
      </h2>

      <div className="space-y-3 mb-6">
        {conditions.length === 0 ? (
          <div className="text-slate-400 italic text-sm py-4 border-2 border-dashed border-slate-100 rounded-lg text-center">
            No filters applied yet. All pending orders will be selected.
          </div>
        ) : (
          conditions.map((c, idx) => (
            <div key={c.id} className="flex items-center gap-2 animate-in fade-in slide-in-from-left-2">
              {idx > 0 && (
                <span className="bg-orange-100 text-orange-600 text-[10px] font-bold px-2 py-1 rounded">
                  {c.joiner}
                </span>
              )}
              <div className="flex-1 flex items-center gap-2 bg-slate-50 border border-slate-200 p-2 rounded-lg text-sm">
                <span className="font-semibold text-slate-600">{c.field}</span>
                <span className="text-slate-400">{c.operator}</span>
                <span className="bg-white px-2 py-0.5 border border-slate-200 rounded font-medium">{c.value}</span>
                <button onClick={() => onRemove(c.id)} className="ml-auto text-slate-400 hover:text-red-500">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-4 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-200">
        {conditions.length > 0 && (
          <select 
            value={newCondition.joiner}
            onChange={e => setNewCondition({...newCondition, joiner: e.target.value as any})}
            className="p-2 bg-white border border-slate-200 rounded-md text-sm outline-none focus:ring-2 focus:ring-[#00A79D]/20"
          >
            <option value="AND">AND</option>
            <option value="OR">OR</option>
          </select>
        )}
        <select 
          value={newCondition.field}
          onChange={e => setNewCondition({...newCondition, field: e.target.value})}
          className="p-2 bg-white border border-slate-200 rounded-md text-sm outline-none focus:ring-2 focus:ring-[#00A79D]/20"
        >
          {FIELDS.map(f => <option key={f} value={f}>{f}</option>)}
        </select>
        <select 
          value={newCondition.operator}
          onChange={e => setNewCondition({...newCondition, operator: e.target.value})}
          className="p-2 bg-white border border-slate-200 rounded-md text-sm outline-none focus:ring-2 focus:ring-[#00A79D]/20"
        >
          {OPERATORS.map(o => <option key={o} value={o}>{o}</option>)}
        </select>
        <div className="flex gap-2">
          <input 
            type="text"
            value={newCondition.value}
            onChange={e => setNewCondition({...newCondition, value: e.target.value})}
            placeholder="Value..."
            className="flex-1 p-2 bg-white border border-slate-200 rounded-md text-sm outline-none focus:ring-2 focus:ring-[#00A79D]/20"
          />
          <button 
            onClick={handleAdd}
            className="bg-[#00A79D] text-white p-2 rounded-md hover:bg-[#008d84] transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MOCK_SCENARIOS } from '../constants';

export const SelectionSummary: React.FC = () => {
  const [selectedId, setSelectedId] = useState(MOCK_SCENARIOS[1].id);

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-2xl font-bold text-slate-800">Ready to Launch Orchestration?</h2>
        <p className="text-slate-500">Review your final selection and trigger the wave execution.</p>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {MOCK_SCENARIOS.map(sc => (
          <div 
            key={sc.id} 
            onClick={() => setSelectedId(sc.id)}
            className={`p-6 rounded-2xl border-2 transition-all cursor-pointer relative overflow-hidden ${
              selectedId === sc.id 
                ? 'border-[#00A79D] bg-white shadow-lg ring-4 ring-[#00A79D]/5' 
                : 'border-slate-100 bg-slate-50 hover:border-slate-200 opacity-60'
            }`}
          >
            {selectedId === sc.id && (
              <div className="absolute top-0 right-0 bg-[#00A79D] text-white px-4 py-1 rounded-bl-xl text-[10px] font-bold tracking-widest uppercase">
                Selected Strategy
              </div>
            )}

            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                  selectedId === sc.id ? 'bg-[#00A79D] text-white' : 'bg-slate-200 text-slate-400'
                }`}>
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                </div>
                <div>
                  <h3 className="font-bold text-lg">{sc.name}</h3>
                  <p className="text-xs text-slate-500">{sc.description}</p>
                </div>
              </div>
              <div className="hidden sm:flex items-center gap-6">
                 <div className="text-center">
                   <p className="text-[10px] text-slate-400 font-bold uppercase">KPI: Speed</p>
                   <p className="text-sm font-bold text-[#00A79D]">{sc.metrics.deliveryTime}d</p>
                 </div>
                 <div className="text-center">
                   <p className="text-[10px] text-slate-400 font-bold uppercase">KPI: Rate</p>
                   <p className="text-sm font-bold text-slate-800">{sc.metrics.fulfillmentRate}%</p>
                 </div>
              </div>
            </div>

            <div className="flex flex-wrap gap-2">
              {sc.rules.map((rule, i) => (
                <span key={i} className={`text-[10px] px-2 py-1 rounded-full border ${
                  selectedId === sc.id ? 'bg-[#00A79D]/5 border-[#00A79D]/20 text-[#00A79D]' : 'bg-slate-200/50 border-slate-300 text-slate-500'
                }`}>
                  {rule}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>

      <div className="bg-slate-900 text-white p-8 rounded-2xl shadow-xl flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="space-y-1 text-center md:text-left">
          <p className="text-emerald-400 font-bold text-xs uppercase tracking-[0.2em]">Ready for Dispatch</p>
          <p className="text-xl font-medium">Start wave orchestration for <span className="text-emerald-400">142 orders</span></p>
          <p className="text-xs text-slate-400">Estimated processing time: ~4.5 seconds</p>
        </div>
        <button className="bg-[#00A79D] hover:bg-[#008d84] text-white px-8 py-4 rounded-xl font-bold shadow-lg shadow-emerald-900/40 transition-transform active:scale-95 flex items-center gap-3">
          Launch Wave
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Header, Sidebar } from './components/Layout';
import { Stepper } from './components/Stepper';
import { ConditionBuilder } from './components/ConditionBuilder';
import { OrchestrationScenarios } from './components/OrchestrationScenarios';
import { ResultsVisualization } from './components/ResultsVisualization';
import { ScenarioComparison } from './components/ScenarioComparison';
import { SelectionSummary } from './components/SelectionSummary';
import { Step, Condition } from './types';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<Step>(Step.OrderSelection);
  const [conditions, setConditions] = useState<Condition[]>([]);

  const addCondition = (c: Condition) => setConditions(prev => [...prev, c]);
  const removeCondition = (id: string) => setConditions(prev => prev.filter(c => c.id !== id));

  const renderStepContent = () => {
    switch (currentStep) {
      case Step.OrderSelection:
        return <ConditionBuilder conditions={conditions} onAdd={addCondition} onRemove={removeCondition} />;
      case Step.OrchestrationScenarios:
        return <OrchestrationScenarios />;
      case Step.ResultsVisualization:
        return <ResultsVisualization />;
      case Step.Comparison:
        return <ScenarioComparison />;
      case Step.FinalSelection:
        return <SelectionSummary />;
      default:
        return null;
    }
  };

  const nextStep = () => {
    if (currentStep < 5) setCurrentStep(prev => (prev + 1) as Step);
  };

  const prevStep = () => {
    if (currentStep > 1) setCurrentStep(prev => (prev - 1) as Step);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans selection:bg-[#00A79D]/30 selection:text-[#00A79D]">
      <Sidebar />
      <div className="flex-1 flex flex-col min-w-0">
        <Header />

        <main className="p-4 md:p-8 flex-1 max-w-7xl mx-auto w-full">
          <div className="mb-8 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div>
              <h1 className="text-2xl font-bold text-slate-800">Wave Orchestration Management</h1>
              <p className="text-sm text-slate-500">Configure, simulate, and optimize your order fulfillment logic.</p>
            </div>
            <div className="flex items-center gap-3">
              <button className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-semibold text-slate-600 hover:bg-slate-50 transition-colors">
                Save Draft
              </button>
              <button className="px-4 py-2 bg-[#2D3E50] text-white rounded-lg text-sm font-semibold hover:bg-slate-800 transition-colors flex items-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                Preview Draft
              </button>
            </div>
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-4 md:p-8 mb-8">
            <Stepper currentStep={currentStep} />
          </div>

          <div className="animate-in fade-in duration-500 slide-in-from-bottom-2">
            {renderStepContent()}
          </div>

          <div className="mt-8 flex items-center justify-between py-6 border-t border-slate-200 bg-slate-50/50 -mx-4 md:-mx-8 px-4 md:px-8 sticky bottom-0 z-40 backdrop-blur-md">
            <button
              onClick={prevStep}
              disabled={currentStep === 1}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${
                currentStep === 1 
                  ? 'text-slate-300 cursor-not-allowed' 
                  : 'text-slate-600 bg-white border border-slate-200 hover:border-slate-300 hover:bg-slate-50'
              }`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
              Previous Step
            </button>

            <div className="hidden sm:flex items-center gap-2">
              {[1,2,3,4,5].map(i => (
                <div key={i} className={`w-1.5 h-1.5 rounded-full transition-all duration-300 ${currentStep === i ? 'w-6 bg-[#00A79D]' : 'bg-slate-200'}`} />
              ))}
            </div>

            <button
              onClick={nextStep}
              disabled={currentStep === 5}
              className={`flex items-center gap-2 px-8 py-2.5 rounded-xl font-bold text-sm transition-all ${
                currentStep === 5
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
                  : 'bg-[#00A79D] text-white hover:bg-[#008d84] shadow-lg shadow-emerald-900/10 hover:-translate-y-0.5'
              }`}
            >
              {currentStep === 4 ? 'Review & Launch' : 'Continue'}
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
            </button>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { Stepper } from './components/Stepper';
import { ConditionBuilder } from './components/ConditionBuilder';
import { OrchestrationScenarios } from './components/OrchestrationScenarios';
import { ResultsVisualization } from './components/ResultsVisualization';
import { ScenarioComparison } from './components/ScenarioComparison';
import { SelectionSummary } from './components/SelectionSummary';
import { Step, Condition } from './types';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<Step>(Step.OrderSelection);
  const [conditions, setConditions] = useState<Condition[]>([]);

  const addCondition = (c: Condition) => setConditions(prev => [...prev, c]);
  const removeCondition = (id: string) => setConditions(prev => prev.filter(c => c.id !== id));

  const renderStepContent = () => {
    switch (currentStep) {
      case Step.OrderSelection:
        return <ConditionBuilder conditions={conditions} onAdd={addCondition} onRemove={removeCondition} />;
      case Step.OrchestrationScenarios:
        return <OrchestrationScenarios />;
      case Step.ResultsVisualization:
        return <ResultsVisualization />;
      case Step.Comparison:
        return <ScenarioComparison />;
      case Step.FinalSelection:
        return <SelectionSummary />;
      default:
        return null;
    }
  };

  const nextStep = () => {
    if (currentStep < 5) setCurrentStep(prev => (prev + 1) as Step);
  };

  const prevStep = () => {
    if (currentStep > 1) setCurrentStep(prev => (prev - 1) as Step);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans selection:bg-[#00A79D]/30 selection:text-[#00A79D] py-8">
      <div className="max-w-7xl mx-auto px-4 md:px-8">
        {/* New Integrated Branding Block */}
        <div className="mb-10 flex flex-col sm:flex-row sm:items-end justify-between gap-6 border-b border-slate-200 pb-8">
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 bg-[#00A79D] rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-xl shadow-emerald-500/20">OS</div>
            <div>
              <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight leading-none">Wave Orchestrator</h1>
              <p className="text-slate-500 font-medium mt-2">Enterprise-grade order fulfillment logic & simulation</p>
