                        </div>
                        <div className="w-[1px] h-6 bg-slate-100 hidden md:block"></div>
                        <div className="space-y-0.5">
                           <span className="text-[9px] font-bold text-[#00A79D] uppercase tracking-widest block">Next Run</span>
                           <span className="text-xs font-bold text-[#00A79D] block whitespace-nowrap">
                             {strategy.nextExecution ? strategy.nextExecution : (strategy.status === 'Active' ? 'Pending' : 'Manual')}
                           </span>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center justify-end gap-2">
                        <button 
                          onClick={() => onSelect(strategy)}
                          className="px-4 py-2 bg-[#00A79D] text-white text-xs font-bold rounded-xl hover:bg-[#008d84] transition-all shadow-md shadow-emerald-500/10"
                        >
                          Select
                        </button>
                        <button 
                          onClick={() => onEdit(strategy)}
                          className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-xl transition-all"
                          title="Edit Logic"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                        </button>
                        <button 
                          onClick={() => {
                            setShowScheduleId(showScheduleId === strategy.id ? null : strategy.id);
                            // Initial manual values
                            if (showScheduleId !== strategy.id) {
                              setManualTimes(['08:00', '14:00', '20:00']);
                            }
                          }}
                          className={`p-2 rounded-xl transition-all ${showScheduleId === strategy.id ? 'bg-orange-50 text-orange-600' : 'text-slate-400 hover:text-orange-500 hover:bg-orange-50'}`}
                          title="Schedule"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        </button>
                      </div>
                    </td>
                  </tr>
                  {showScheduleId === strategy.id && (
                    <tr className="bg-orange-50/10 border-l-4 border-orange-400">
                      <td colSpan={4} className="px-8 py-8">
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 animate-in slide-in-from-top-2 duration-300">

                          {/* Days Selection */}
                          <div className="space-y-5">
                            <div className="flex items-center justify-between">
                              <div className="flex items-center gap-3">
                                <div className="w-8 h-8 bg-orange-100 rounded-lg flex items-center justify-center text-orange-600">
                                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                                </div>
                                <h4 className="text-sm font-bold text-orange-900 uppercase tracking-wide">Execution Days</h4>
                              </div>
                              <div className="flex gap-2">
                                 {['weekdays', 'weekends', 'all', 'clear'].map(preset => (
                                   <button
                                     key={preset}
                                     onClick={() => setDayPreset(preset as any)}
                                     className="px-3 py-1 bg-white border border-orange-200 rounded-full text-[10px] font-bold text-orange-600 hover:bg-orange-100 transition-all uppercase tracking-tighter"
                                   >
                                     {preset}
                                   </button>
                                 ))}
                              </div>
                            </div>
                            <div className="flex flex-wrap gap-2">
                              {DAYS.map((day) => (
                                <button
                                  key={day.value}
                                  onClick={() => toggleDay(day.value)}
                                  className={`px-5 py-2 rounded-xl font-bold text-sm transition-all border ${
                                    selectedDays.includes(day.value)
                                      ? 'bg-orange-500 border-orange-600 text-white shadow-md shadow-orange-500/20'
                                      : 'bg-white border-orange-200 text-orange-400 hover:border-orange-400 hover:text-orange-600'
                                  }`}
                                >
                                  {day.full}
                                </button>
                              ))}
                            </div>
                          </div>

                          {/* Manual Hours Selection */}
                          <div className="space-y-5">
                            <div className="flex items-center gap-3">
                              <div className="w-8 h-8 bg-orange-100 rounded-lg flex items-center justify-center text-orange-600">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                              </div>
                              <h4 className="text-sm font-bold text-orange-900 uppercase tracking-wide">Manual Execution Times</h4>
                            </div>

                            <div className="flex items-center gap-3 bg-white p-3 rounded-2xl border border-orange-100 shadow-sm">
                              <input 
                                type="time" 
                                value={newTime}
                                onChange={(e) => setNewTime(e.target.value)}
                                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-orange-500/20"
                              />
                              <button 
                                onClick={addTime}
                                className="bg-orange-500 text-white px-6 py-2 rounded-xl text-sm font-bold hover:bg-orange-600 transition-all flex items-center gap-2"
                              >
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                                Add Time
                              </button>
                            </div>

                            <div className="flex flex-wrap gap-2">
                              {manualTimes.length === 0 ? (
                                <p className="text-xs text-slate-400 italic py-2">No execution times added yet.</p>
                              ) : (
                                manualTimes.map(time => (
                                  <div key={time} className="flex items-center gap-2 bg-orange-50 border border-orange-200 px-4 py-2 rounded-xl animate-in zoom-in-90 duration-200">
                                    <span className="text-sm font-black text-orange-700">{time}</span>
                                    <button 
                                      onClick={() => removeTime(time)}
                                      className="text-orange-300 hover:text-red-500 transition-colors"
                                    >
                                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                                    </button>
                                  </div>
                                ))
                              )}
                            </div>
                          </div>

                          {/* Summary & Actions */}
                          <div className="lg:col-span-2 flex flex-col md:flex-row items-center justify-between pt-8 border-t border-orange-200 gap-6">
                            <div className="flex-1">
                              <div className="bg-orange-50/50 p-4 rounded-2xl border border-orange-100 inline-block">
                                <p className="text-sm font-medium text-orange-800 leading-relaxed">
                                  {selectedDays.length > 0 && manualTimes.length > 0 ? (
                                    <>
                                      This strategy is scheduled for <span className="font-bold">{manualTimes.length} execution(s)</span> daily 
                                      on <span className="font-bold">
                                        {selectedDays.length === 7 ? 'Every Day' : selectedDays.map(dv => DAYS.find(d => d.value === dv)?.label).join(', ')}
                                      </span> 
                                      at: <span className="font-bold text-orange-600">{manualTimes.join(', ')}</span>.
                                    </>
                                  ) : (
                                    "Please select execution days and add at least one manual time."
                                  )}
                                </p>
                              </div>
                            </div>
                            <div className="flex gap-3 w-full md:w-auto">
                              <button 
                                onClick={() => setShowScheduleId(null)}
                                className="flex-1 md:flex-none bg-orange-600 text-white px-10 py-3 rounded-xl text-base font-bold hover:bg-orange-700 transition-all shadow-xl shadow-orange-600/30"
                              >
                                Save Schedule
                              </button>
                              <button 
                                onClick={() => setShowScheduleId(null)}
                                className="flex-1 md:flex-none text-orange-500 bg-white border border-orange-200 px-8 py-3 rounded-xl text-base font-bold hover:bg-orange-50 transition-all"
                              >
                                Cancel
                              </button>
                            </div>
                          </div>
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Condition } from '../types';
import { FIELDS, OPERATORS } from '../constants';

interface ConditionBuilderProps {
  conditions: Condition[];
  onAdd: (c: Condition) => void;
  onRemove: (id: string) => void;
}

export const ConditionBuilder: React.FC<ConditionBuilderProps> = ({ conditions, onAdd, onRemove }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newCondition, setNewCondition] = useState<Partial<Condition>>({
    field: FIELDS[0],
    operator: OPERATORS[0],
    value: '',
    joiner: 'AND'
  });

  const handleAdd = () => {
    if (newCondition.value) {
      onAdd({
        id: Math.random().toString(36).substr(2, 9),
        field: newCondition.field!,
        operator: newCondition.operator!,
        value: newCondition.value!,
        joiner: conditions.length > 0 ? newCondition.joiner : undefined
      });
      setNewCondition({ ...newCondition, value: '' });
      setIsModalOpen(false);
    }
  };

  return (
    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl shadow-slate-200/50">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-xl font-black text-slate-900 flex items-center gap-3">
            <div className="w-10 h-10 bg-emerald-50 text-[#00A79D] rounded-xl flex items-center justify-center">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
            </div>
            Order Selection Filters
          </h2>
          <p className="text-slate-500 text-sm mt-1">Define which orders should be included in this orchestration wave.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-[#00A79D] text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-3 shadow-lg shadow-emerald-500/20 hover:bg-[#008d84] transition-all hover:-translate-y-0.5"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
          Add Filter
        </button>
      </div>

      <div className="space-y-4">
        {conditions.length === 0 ? (
          <div className="text-slate-400 italic text-sm py-12 border-2 border-dashed border-slate-100 rounded-[2rem] text-center bg-slate-50/30">
            <div className="w-12 h-12 bg-white border border-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
            </div>
            No filters applied yet. All pending orders will be selected.
          </div>
        ) : (
          conditions.map((c, idx) => (
            <div key={c.id} className="flex items-center gap-4 animate-in fade-in slide-in-from-left-4 duration-300">
              {idx > 0 && (
                <div className="bg-orange-100 text-orange-600 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest border border-orange-200">
                  {c.joiner}
                </div>
              )}
              <div className="flex-1 flex items-center gap-4 bg-white border border-slate-200 p-4 rounded-2xl text-sm shadow-sm group hover:border-[#00A79D]/30 transition-all">
                <div className="w-2 h-2 rounded-full bg-[#00A79D]"></div>
                <span className="font-bold text-slate-800">{c.field}</span>
                <span className="text-slate-400 font-medium italic">{c.operator}</span>
                <span className="bg-emerald-50 text-[#00A79D] px-3 py-1 border border-emerald-100 rounded-xl font-bold">{c.value}</span>
                <button 
                  onClick={() => onRemove(c.id)} 
                  className="ml-auto w-8 h-8 flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Filter Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-black text-slate-900">New Selection Filter</h3>
                <p className="text-slate-500 text-sm">Target specific orders for orchestration.</p>
              </div>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="w-10 h-10 flex items-center justify-center text-slate-400 hover:bg-slate-100 rounded-2xl transition-all"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="p-8 space-y-6">
              {conditions.length > 0 && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Logical Joiner</label>
                  <div className="flex gap-2">
                    {['AND', 'OR'].map(joiner => (
                      <button
                        key={joiner}
                        onClick={() => setNewCondition({...newCondition, joiner: joiner as any})}
                        className={`flex-1 py-3 rounded-2xl text-sm font-bold border transition-all ${
                          newCondition.joiner === joiner 
                            ? 'bg-orange-500 border-orange-600 text-white shadow-lg shadow-orange-500/20' 
                            : 'bg-white border-slate-200 text-slate-400 hover:border-orange-300'
                        }`}
                      >
                        {joiner}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Attribute Field</label>
                <select 
                  value={newCondition.field}
                  onChange={e => setNewCondition({...newCondition, field: e.target.value})}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold text-slate-800 outline-none focus:ring-4 focus:ring-[#00A79D]/10 focus:border-[#00A79D] transition-all appearance-none cursor-pointer"
                >
                  {FIELDS.map(f => <option key={f} value={f}>{f}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Operator</label>
                  <select 
                    value={newCondition.operator}
                    onChange={e => setNewCondition({...newCondition, operator: e.target.value})}
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold text-slate-800 outline-none focus:ring-4 focus:ring-[#00A79D]/10 focus:border-[#00A79D] transition-all appearance-none cursor-pointer"
                  >
                    {OPERATORS.map(o => <option key={o} value={o}>{o}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Comparison Value</label>
                  <input 
                    type="text"
                    value={newCondition.value}
                    onChange={e => setNewCondition({...newCondition, value: e.target.value})}
                    placeholder="Type value..."
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold text-slate-800 outline-none focus:ring-4 focus:ring-[#00A79D]/10 focus:border-[#00A79D] transition-all placeholder-slate-300"
                  />
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="flex-1 px-6 py-4 rounded-2xl font-bold text-slate-500 hover:bg-slate-100 transition-all border border-slate-200"
              >
                Cancel
              </button>
              <button 
                onClick={handleAdd}
                className="flex-2 bg-[#00A79D] text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-500/20 hover:bg-[#008d84] transition-all"
              >
                Confirm Filter
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export interface Condition {
  id: string;
  field: string;
  operator: string;
  value: string;
  joiner?: 'AND' | 'OR';
  infoFieldName?: string;
  infoFieldType?: string;
}

export interface Scenario {
  id: string;
  name: string;
  description: string;
  rules: string[];
  metrics: {
    fulfillmentRate: number;
    shippingCost: number;
    deliveryTime: number;
    carbonFootprint: number;
    orderCount: number;
    itemCount: number;
  };
  lastExecuted?: string;
  nextExecution?: string;
  status?: 'Active' | 'Draft' | 'Scheduled';
}

export interface Order {
  id: string;
  client: string;
  priority: 'P1' | 'P2' | 'P3';
  sku: string;
  quantity: number;
  date: string;
  channel: string;
  status: string;
  proposedStockPoint?: string;
}

export enum Step {
  StrategyManagement = 0,
  OrderSelection = 1,
  OrchestrationScenarios = 2,
  ResultsVisualization = 3,
  Comparison = 4,
  FinalSelection = 5
}

import React, { useState } from 'react';
import { Condition } from '../types';
import { FIELDS, OPERATORS } from '../constants';

interface ConditionBuilderProps {
  conditions: Condition[];
  onAdd: (c: Condition) => void;
