export const ScenarioComparison: React.FC = () => {
  // Liste des IDs des stratégies sélectionnées pour la comparaison
  const [selectedScenarioIds, setSelectedScenarioIds] = useState<string[]>(
    MOCK_SCENARIOS.slice(0, 3).map(s => s.id)
  );

  // Simulation de données de comparaison pour les stratégies sélectionnées
  const orderComparisonData = useMemo(() => {
    const strategies = MOCK_SCENARIOS.filter(s => selectedScenarioIds.includes(s.id));
    const stockPoints = ['WH-PARIS-01', 'WH-LYON-02', 'STORE-NICE-04', 'WH-BERLIN-01'];

    if (strategies.length === 0) return [];

    return MOCK_ORDERS.map((order, idx) => {
      // Simulation déterministe mais variée des sélections par stratégie
      const selections = strategies.map((s, sIdx) => {
        // Logique fictive : certaines commandes ne sont pas dispos dans toutes les stratégies
        const isMatched = (idx + sIdx) % 4 !== 0;
        return {
          strategyId: s.id,
          strategyName: s.name,
          isMatched,
          proposedStock: isMatched ? stockPoints[(idx + sIdx) % stockPoints.length] : null
        };
      });

      const matchCount = selections.filter(s => s.isMatched).length;

      return {
        ...order,
        selections,
        matchCount,
        totalStrategies: strategies.length
      };
    }).sort((a, b) => b.matchCount - a.matchCount);
  }, [selectedScenarioIds]);

  const toggleScenario = (id: string) => {
    setSelectedScenarioIds(prev => 
      prev.includes(id) 
        ? prev.filter(sid => sid !== id) 
        : [...prev, id]
    );
  };

  const selectedScenarios = MOCK_SCENARIOS.filter(s => selectedScenarioIds.includes(s.id));

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Sélecteur de stratégies */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl shadow-slate-200/50">
